import { useState, useEffect } from "react";
import "./App.css";

const VEHICLE_TYPES = [
  { label: "Car", icon: "🚗" },
  { label: "Truck", icon: "🚛" },
  { label: "Van", icon: "🚐" },
  { label: "Bike", icon: "🏍️" },
  { label: "Bus", icon: "🚌" },
  { label: "Other", icon: "🚙" },
];

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3001";

function calcTimeDiff(inTime, outTime) {
  if (!inTime || !outTime) return "";
  const diff = new Date(outTime) - new Date(inTime);
  if (diff < 0) return "Invalid";
  const h = Math.floor(diff / 3600000);
  const m = Math.floor((diff % 3600000) / 60000);
  return `${h}h ${m}m`;
}

export default function App() {
  const [dark, setDark] = useState(false);
  const [form, setForm] = useState({
    driverName: "",
    purpose: "",
    vehicleType: "",
    inTime: "",
    outTime: "",
    inKm: "",
    outKm: "",
  });
  const [timeDiff, setTimeDiff] = useState("");
  const [kmDiff, setKmDiff] = useState("");
  const [loading, setLoading] = useState(false);
  const [toast, setToast] = useState({ show: false, msg: "", type: "success" });
  const [errors, setErrors] = useState({});

  useEffect(() => {
    document.body.className = dark ? "dark" : "";
  }, [dark]);

  useEffect(() => {
    setTimeDiff(calcTimeDiff(form.inTime, form.outTime));
  }, [form.inTime, form.outTime]);

  useEffect(() => {
    const diff = parseFloat(form.outKm) - parseFloat(form.inKm);
    setKmDiff(!isNaN(diff) && diff >= 0 ? diff.toFixed(1) + " km" : "");
  }, [form.inKm, form.outKm]);

  const showToast = (msg, type = "success") => {
    setToast({ show: true, msg, type });
    setTimeout(() => setToast((t) => ({ ...t, show: false })), 3500);
  };

  const validate = () => {
    const e = {};
    if (!form.driverName.trim()) e.driverName = "Required";
    if (!form.purpose.trim()) e.purpose = "Required";
    if (!form.vehicleType) e.vehicleType = "Select a vehicle type";
    if (!form.inTime) e.inTime = "Required";
    if (!form.outTime) e.outTime = "Required";
    if (form.inTime && form.outTime && new Date(form.outTime) <= new Date(form.inTime))
      e.outTime = "Must be after In Time";
    if (!form.inKm) e.inKm = "Required";
    if (!form.outKm) e.outKm = "Required";
    if (form.inKm && form.outKm && parseFloat(form.outKm) < parseFloat(form.inKm))
      e.outKm = "Must be ≥ In KM";
    return e;
  };

  const handleChange = (e) => {
    setForm((f) => ({ ...f, [e.target.name]: e.target.value }));
    setErrors((err) => ({ ...err, [e.target.name]: "" }));
  };

  const handleVehicle = (v) => {
    setForm((f) => ({ ...f, vehicleType: v }));
    setErrors((err) => ({ ...err, vehicleType: "" }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length) { setErrors(errs); return; }

    setLoading(true);
    try {
      const payload = {
        driver_name: form.driverName.trim(),
        purpose: form.purpose.trim(),
        vehicle_type: form.vehicleType,
        in_time: form.inTime,
        out_time: form.outTime,
        time_difference: timeDiff,
        in_km: parseFloat(form.inKm),
        out_km: parseFloat(form.outKm),
        km_difference: parseFloat((parseFloat(form.outKm) - parseFloat(form.inKm)).toFixed(1)),
      };

      const res = await fetch(`${API_URL}/api/driver-log`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      const data = await res.json();
      if (res.ok) {
        showToast("Driver log saved successfully!", "success");
        setForm({ driverName:"", purpose:"", vehicleType:"", inTime:"", outTime:"", inKm:"", outKm:"" });
        setTimeDiff(""); setKmDiff(""); setErrors({});
      } else {
        showToast(data.message || "Server error", "error");
      }
    } catch {
      showToast("Could not connect to server. Check backend.", "error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="app">
      <div className="header">
        <div className="header-left">
          <div className="eyebrow">Fleet Management</div>
          <h1 className="title">Driver <span>Log</span></h1>
          <p className="subtitle">Record vehicle trips and track mileage in real-time</p>
        </div>
        <button className="theme-btn" onClick={() => setDark(!dark)}>
          <span className="theme-icon">{dark ? "☀️" : "🌙"}</span>
          <span>{dark ? "Light" : "Dark"}</span>
        </button>
      </div>

      <form onSubmit={handleSubmit} noValidate>

        {/* Driver Info */}
        <div className="card">
          <div className="section-label">Driver Information</div>
          <div className="grid-2">
            <div className="field full">
              <label>Driver Name <span className="req">*</span></label>
              <input type="text" name="driverName" value={form.driverName}
                onChange={handleChange} placeholder="Enter full name"
                className={errors.driverName ? "error" : ""} />
              {errors.driverName && <span className="err-msg">{errors.driverName}</span>}
            </div>
            <div className="field full">
              <label>Purpose of Trip <span className="req">*</span></label>
              <input type="text" name="purpose" value={form.purpose}
                onChange={handleChange} placeholder="e.g. Client Visit, Delivery…"
                className={errors.purpose ? "error" : ""} />
              {errors.purpose && <span className="err-msg">{errors.purpose}</span>}
            </div>
          </div>
        </div>

        {/* Vehicle */}
        <div className="card">
          <div className="section-label">Vehicle Details</div>
          <div className="field">
            <label>Vehicle Type <span className="req">*</span></label>
            <div className="vehicle-options">
              {VEHICLE_TYPES.map((v) => (
                <div key={v.label}
                  className={`vehicle-opt${form.vehicleType === v.label ? " selected" : ""}`}
                  onClick={() => handleVehicle(v.label)}>
                  <span className="vicon">{v.icon}</span>
                  {v.label}
                </div>
              ))}
            </div>
            {errors.vehicleType && <span className="err-msg">{errors.vehicleType}</span>}
          </div>
        </div>

        {/* Time */}
        <div className="card">
          <div className="section-label">Trip Timing</div>
          <div className="grid-2">
            <div className="field">
              <label>In Time <span className="req">*</span></label>
              <input type="datetime-local" name="inTime" value={form.inTime}
                onChange={handleChange} className={errors.inTime ? "error" : ""} />
              {errors.inTime && <span className="err-msg">{errors.inTime}</span>}
            </div>
            <div className="field">
              <label>Out Time <span className="req">*</span></label>
              <input type="datetime-local" name="outTime" value={form.outTime}
                onChange={handleChange} className={errors.outTime ? "error" : ""} />
              {errors.outTime && <span className="err-msg">{errors.outTime}</span>}
            </div>
            <div className="field full">
              <label className="auto-label">
                <span>Time Difference</span>
                <span className="auto-badge"><span className="auto-dot"></span>Auto-calculated</span>
              </label>
              <input type="text" value={timeDiff} readOnly className="readonly-field"
                placeholder="Will calculate automatically" />
            </div>
          </div>
        </div>

        {/* KM */}
        <div className="card">
          <div className="section-label">Odometer Readings</div>
          <div className="grid-2">
            <div className="field">
              <label>In KM <span className="req">*</span></label>
              <input type="number" name="inKm" value={form.inKm}
                onChange={handleChange} placeholder="0" min="0"
                className={errors.inKm ? "error" : ""} />
              {errors.inKm && <span className="err-msg">{errors.inKm}</span>}
            </div>
            <div className="field">
              <label>Out KM <span className="req">*</span></label>
              <input type="number" name="outKm" value={form.outKm}
                onChange={handleChange} placeholder="0" min="0"
                className={errors.outKm ? "error" : ""} />
              {errors.outKm && <span className="err-msg">{errors.outKm}</span>}
            </div>
            <div className="field full">
              <label className="auto-label">
                <span>KM Difference</span>
                <span className="auto-badge"><span className="auto-dot"></span>Auto-calculated</span>
              </label>
              <input type="text" value={kmDiff} readOnly className="readonly-field"
                placeholder="Will calculate automatically" />
            </div>
          </div>
        </div>

        {/* Submit */}
        <div className="card submit-card">
          <div className="submit-row">
            <p className="submit-info">Fields marked <span className="req">*</span> are required</p>
            <button type="submit" className={`submit-btn${loading ? " loading" : ""}`} disabled={loading}>
              <span>{loading ? "⟳" : "✓"}</span>
              <span>{loading ? "Submitting…" : "Submit Log"}</span>
            </button>
          </div>
        </div>

      </form>

      {/* Toast */}
      <div className={`toast ${toast.type}${toast.show ? " show" : ""}`}>
        <span>{toast.type === "success" ? "✓" : "✕"}</span>
        <span>{toast.msg}</span>
      </div>
    </div>
  );
}
